#include <iostream>
#include <numeric>
#include <cmath>
#include <string>
#include <sstream>
#include <stdexcept>
#include <utility>

// Helper GCD function (efficient Euclidean algorithm)
int gcd_2145(int a, int b) {
    a = std::abs(a);
    b = std::abs(b);
    while (b) {
        a %= b;
        std::swap(a, b);
    }
    return a;
}

class Fraction {
private:
    int numerator;
    int denominator;

    void simplify() {
        if (numerator == 0) {
            denominator = 1;
            return;
        }

        int common = gcd_2145(numerator, denominator);
        numerator /= common;
        denominator /= common;

        if (denominator < 0) {
            numerator = -numerator;
            denominator = -denominator;
        }
    }

public:
    Fraction(int num = 0, int den = 1) : numerator(num), denominator(den) {
        if (denominator == 0) {
            throw std::invalid_argument("Denominator cannot be zero.");
        }
        simplify();
    }

    Fraction operator*(const Fraction& other) const {
        return Fraction(
            this->numerator * other.numerator,
            this->denominator * other.denominator
        );
    }

    friend std::ostream& operator<<(std::ostream& os, const Fraction& f) {
        os << f.numerator << "/" << f.denominator;
        return os;
    }
};

void run_test(const std::string& input_str, const std::string& expected_output) {
    std::istringstream iss(input_str);
    char slash;
    int n1, d1, n2, d2;

    try {
        iss >> n1 >> slash >> d1;
        Fraction f1(n1, d1);

        iss >> n2 >> slash >> d2;
        Fraction f2(n2, d2);

        Fraction result = f1 * f2;

        std::ostringstream oss;
        oss << result;
        std::string actual_output = oss.str();

        if (actual_output == expected_output) {
            std::cout << "Test passed: " << input_str << " -> " << actual_output << "\n";
        } else {
            std::cout << "Test failed: " << input_str << ". Expected: " << expected_output << ", Got: " << actual_output << "\n";
        }
    } catch (const std::invalid_argument& e) {
        if (expected_output == "ERROR: " + std::string(e.what())) {
            std::cout << "Test passed (exception): " << input_str << " -> " << e.what() << "\n";
        }
    } catch (const std::exception& e) {
        std::cout << "Test failed (unexpected runtime error): " << input_str << ". Error: " << e.what() << "\n";
    } catch (...) {
        std::cout << "Test failed (unknown error - possibly crash or division by zero): " << input_str << "\n";
    }
}

int main() {
    run_test("1/2 3/4", "3/8");
    run_test("2/3 3/2", "1/1");
    run_test("-2/4 1/1", "-1/2");
    run_test("2/-4 1/1", "-1/2");
    run_test("0/5 7/8", "0/1");
    run_test("5/1 2/1", "10/1");
    run_test("-2/-4 1/1", "1/2");
    run_test("1/0 1/1", "ERROR: Denominator cannot be zero.");
    return 0;
}
